const eng = $input.first().json;
const trig = $('Execute Workflow Trigger').first().json;
const asset = trig.asset_value || '';
const moduleType = (trig.module_type || 'passive').toString();

if (!eng || !eng.id) {
  return [{ json: { allowed: false, reason: 'engagement_not_found', asset_value: asset, module_type: moduleType } }];
}
if (eng.status !== 'active') {
  return [{ json: { allowed: false, reason: 'engagement_not_active', status: eng.status, asset_value: asset, engagement_id: trig.engagement_id, module_type: moduleType } }];
}
const now = new Date();
const start = new Date(eng.testing_window_start);
const end = new Date(eng.testing_window_end);
if (now < start || now > end) {
  return [{ json: { allowed: false, reason: 'outside_testing_window', window_start: eng.testing_window_start, window_end: eng.testing_window_end, asset_value: asset, engagement_id: eng.id, module_type: moduleType } }];
}

const offensive = moduleType.startsWith('wifi_evil_twin') || moduleType.startsWith('mitm_') || moduleType === 'decepticon_autonomous';
if (offensive && !eng.lab_only) {
  return [{ json: { allowed: false, reason: 'offensive_module_outside_lab', asset_value: asset, engagement_id: eng.id, module_type: moduleType } }];
}

return [{ json: { engagement_ok: true, engagement_id: eng.id, rate_limit_profile: eng.rate_limit_profile, lab_only: !!eng.lab_only, asset_value: asset, module_type: moduleType } }];

const rules = $input.all().map(i => i.json);
const triggerData = $('Execute Workflow Trigger').first().json;
const chk = $('Check Engagement Status').first().json;
const assetValue = (triggerData.asset_value || '').toLowerCase().trim().replace(/\.$/,'');
const engId = chk.engagement_id;
const rateProfile = chk.rate_limit_profile;
const moduleType = chk.module_type || 'passive';
const labOnly = !!chk.lab_only;

function normalizeHost(h) {
  return (h||'').toLowerCase().trim().replace(/\.$/,'').replace(/^https?:\/\//,'').split('/')[0];
}

const isWifiOffensive = moduleType.startsWith('wifi_evil_twin') || moduleType.startsWith('mitm_');

let matched = null;
for (const rule of rules) {
  const ruleVal = normalizeHost(rule.value);
  if (isWifiOffensive) {
    // Offensive WiFi/MitM modules must match a wifi_lab or subnet_lab scope rule exactly
    if ((rule.scope_type === 'wifi_lab' || rule.scope_type === 'subnet_lab') && assetValue === ruleVal) {
      matched = rule; break;
    }
  } else if (rule.scope_type === 'domain' || rule.scope_type === 'web_app' || rule.scope_type === 'api') {
    if (assetValue === ruleVal) { matched = rule; break; }
  } else if (rule.scope_type === 'subdomain_wildcard') {
    const base = ruleVal.replace(/^\*\./, '');
    if (assetValue === base || assetValue.endsWith('.' + base)) { matched = rule; break; }
  } else if (rule.scope_type === 'ip') {
    if (assetValue === ruleVal) { matched = rule; break; }
  } else if (rule.scope_type === 'cidr') {
    const [network, bits] = ruleVal.split('/');
    matched = null;
  } else if (rule.scope_type === 'environment') {
    if (assetValue.includes(ruleVal)) { matched = rule; break; }
  } else if (rule.scope_type === 'wifi_lab' || rule.scope_type === 'subnet_lab') {
    // Lab scope rule but request is non-offensive — also match exact for passive lab audits
    if (assetValue === ruleVal) { matched = rule; break; }
  }
}

if (!matched) {
  const reason = isWifiOffensive ? 'offensive_module_target_not_in_lab_scope' : 'out_of_scope';
  return [{ json: { allowed: false, reason, asset_value: assetValue, engagement_id: engId, module_type: moduleType } }];
}

if (isWifiOffensive && !labOnly) {
  return [{ json: { allowed: false, reason: 'offensive_module_outside_lab', asset_value: assetValue, engagement_id: engId, module_type: moduleType } }];
}

return [{ json: { allowed: true, scope_rule_id: matched.id, scope_type: matched.scope_type, asset_value: assetValue, engagement_id: engId, rate_limit_profile: rateProfile, module_type: moduleType, lab_only: labOnly } }];
